<script setup lang="ts">import { watch } from 'vue';import { dashboard } from '../api';import AppShell from '../components/AppShell.vue';import AsyncPanel from '../components/AsyncPanel.vue';import { useAsyncData } from '../composables/useAsyncData';import { useAutoRefresh } from '../composables/useAutoRefresh';import { useFiltersStore } from '../stores/filters';const filters=useFiltersStore();const state=useAsyncData(async()=>(await dashboard.operationAudits({instance_id:filters.instance_id||undefined,limit:200})).items);watch(()=>filters.instance_id,()=>void state.reload());useAutoRefresh(state.reload);</script>
<template><AppShell title="操作审计"><AsyncPanel :loading="state.loading.value" :error="state.error.value" :empty="!state.data.value?.length" @retry="state.reload"><el-table :data="state.data.value"><el-table-column prop="created_at" label="时间"><template #default="s">{{new Date(s.row.created_at).toLocaleString()}}</template></el-table-column><el-table-column prop="operation_type" label="类型"/><el-table-column label="目标"><template #default="s">{{s.row.target_type}} / {{s.row.target_id}}</template></el-table-column><el-table-column prop="actor_id" label="操作人"/><el-table-column prop="after_summary" label="摘要"/></el-table></AsyncPanel></AppShell></template>
